SWEP.PrintName = "Snarks"SWEP.Category = "Half-Life 2"SWEP.Author		= "VALVe"SWEP.DrawWeaponInfoBox	= falseSWEP.BounceWeaponIcon = false SWEP.Spawnable= trueSWEP.AdminSpawnable= trueSWEP.AdminOnly = falseSWEP.ViewModelFOV = 84SWEP.ViewModel = "models/weapons/c_hl2_snark.mdl"SWEP.WorldModel = "models/weapons/w_hl2_snark.mdl"SWEP.ViewModelFlip = falseSWEP.BobScale = 1SWEP.SwayScale = 0SWEP.AutoSwitchTo = falseSWEP.AutoSwitchFrom = falseSWEP.Weight = 0SWEP.Slot = 5SWEP.SlotPos = 6SWEP.UseHands = trueSWEP.HoldType = "grenade"SWEP.FiresUnderwater = trueSWEP.DrawCrosshair = trueSWEP.DrawAmmo = trueSWEP.CSMuzzleFlashes = 1SWEP.Base = "weapon_ply_comgr"--------------------------------------------------------------------------------|SWEP.Throw = 0SWEP.ThrowTimer = CurTime()SWEP.Idle = 0SWEP.IdleTimer = CurTime()--------------------------------------------------------------------------------|SWEP.Primary.ClipSize = -1SWEP.Primary.DefaultClip = 1SWEP.Primary.MaxAmmo = 10SWEP.Primary.Automatic = trueSWEP.Primary.Ammo = "Snarks_CETS"SWEP.Primary.TakeAmmo = 1SWEP.Primary.Delay = 0.3SWEP.Primary.Force = 750SWEP.Primary.Sound = "npc/squeek/sqk_deploy1.wav"--------------------------------------------------------------------------------|SWEP.Secondary.ClipSize = -1SWEP.Secondary.DefaultClip = -1SWEP.Secondary.Automatic = trueSWEP.Secondary.Ammo = "none"--------------------------------------------------------------------------------|SWEP.GrenadeType = "npc_snark_vj_cets"--------------------------------------------------------------------------------|function SWEP:DrawWorldModel()	self:DrawModel()end--------------------------------------------------------------------------------|function SWEP:PrimaryAttack()	if !( self.Throw == 0 ) then return end	if self.Weapon:Ammo1() <= 0 then return end	self.Weapon:SendWeaponAnim( ACT_VM_PULLPIN )	self:SetNextPrimaryFire( CurTime() + self.Primary.Delay )	self:SetNextSecondaryFire( CurTime() + self.Primary.Delay )	self.Throw = 1	self.ThrowTimer = CurTime() + self.Primary.Delay	self.Idle = 1	self:EmitSound("npc/squeek/sqk_deploy1.wav", 90, math.random(90, 110))end--------------------------------------------------------------------------------|function SWEP:Think()	local weapOwn = self:GetOwner()	local function LaunchGrenade(force)		if SERVER then			local entity = ents.Create(self.GrenadeType)			if IsValid(entity) then				local Forward = weapOwn:EyeAngles():Forward()				local Right = weapOwn:EyeAngles():Right()				entity:SetVelocity(weapOwn:EyeAngles():Forward() * 400 + weapOwn:GetVelocity())				entity:SetPos(weapOwn:GetShootPos() + Forward * 24 + Right * 4)				entity:Spawn()				local phys = entity:GetPhysicsObject()				phys:SetVelocity(weapOwn:GetAimVector() * force)				phys:AddAngleVelocity(Vector(math.Rand(-500,500), math.Rand(-500,5000), math.Rand(-500,500)))			end		end		self.Weapon:SendWeaponAnim(ACT_VM_THROW)		self.Owner:SetAnimation(PLAYER_ATTACK1)		self:TakePrimaryAmmo(self.Primary.TakeAmmo)		self.ThrowTimer = CurTime() + self.Primary.Delay	end	if self.Throw == 1 and self.ThrowTimer <= CurTime() and !self.Owner:KeyDown(IN_ATTACK) then		LaunchGrenade(self.Primary.Force)		self.Throw = 2	end	if self.ThrowN == 1 and self.ThrowTimer <= CurTime() and !self.Owner:KeyDown(IN_ATTACK2) then		LaunchGrenade(self.Secondary.Force)		self.ThrowN = 2	end	if self.Idle == 0 and self.IdleTimer <= CurTime() then		if SERVER then self.Weapon:SendWeaponAnim(ACT_VM_IDLE) end		self.Idle = 1	end	if self.Weapon:Ammo1() > self.Primary.MaxAmmo then		self.Owner:SetAmmo(self.Primary.MaxAmmo, self.Primary.Ammo)	end	if (self.Throw == 2 or self.ThrowN == 2) and self.ThrowTimer <= CurTime() then		if self.Weapon:Ammo1() > 0 then			self.Weapon:SendWeaponAnim(ACT_VM_DRAW)			self.Throw, self.ThrowN, self.ThrowTimer = 0, 0, CurTime()			self.Idle, self.IdleTimer = 0, CurTime() + self.Owner:GetViewModel():SequenceDuration()		else			if SERVER then				self.Owner:DropWeapon(self.Weapon)				self.Weapon:Remove()			end		end	endend